#!/usr/bin/env node
/**
 * ROS BMS Permanent Patch Script
 * Run from project root: node patch.js
 * Safe to run multiple times - skips already-applied patches
 */
const fs=require('fs'),path=require('path');
const FILE=path.join(__dirname,'src','App.jsx');
if(!fs.existsSync(FILE)){console.error('src/App.jsx not found');process.exit(1);}
let src=fs.readFileSync(FILE);
const done=[],skipped=[];
function b(hex){return Buffer.from(hex,'hex');}
function ap(label,o,n){if(src.includes(n)){skipped.push(label);return;}
  if(!src.includes(o)){console.error('NOT FOUND: '+label);process.exit(1);}
  const i=src.indexOf(o);src=Buffer.concat([src.slice(0,i),n,src.slice(i+o.length)]);done.push(label);}

// 1. Cashflow sidebar
ap('1. Cashflow sidebar',
  b('2020202020202020202020207b6c6162656c3a2246494e414e4345222c206964733a5b22696e766f69636573222c22657870656e736573225d7d2c'),
  b('2020202020202020202020207b6c6162656c3a2246494e414e4345222c206964733a5b22696e766f69636573222c22657870656e736573222c2263617368666c6f77225d7d2c'));

// 2. cfFY states
ap('2. cfFY states',
  b('2020636f6e7374205b6f70656e4d656e752c7365744f70656e4d656e755d3d7573655374617465286e756c6c293b0d0a'),
  b(''));

// 3. ESF state
ap('3. ESF state',
  b('20202020707572416d6f756e743a20202073616c652e707572416d6f756e747c7c22222c0d0a20207d293b0d0a2020636f6e7374207365743d286b2c76293d3e736574466f726d28663d3e287b2e2e2e662c5b6b5d3a767d29293b0d0a0d0a2020636f6e7374206861734c696e6573'),
  b(''));

// 4. ESF wrapper+customer
ap('4. ESF wrapper+customer',
  b(''),
  b(''));

// 5. ESF pricing+payment
ap('5. ESF pricing+payment',
  b(''),
  b(''));

// 6. ESF footer
ap('6. ESF footer',
  b(''),
  b(''));

// 7. Detail Paid By
ap('7. Detail Paid By',
  b(''),
  b(''));

// 8. NSF Paid By field
ap('8. NSF Paid By field',
  b(''),
  b(''));

// 9. NSF shop invoice
ap('9. NSF shop invoice',
  b(''),
  b(''));

// 10. Cashflow IIFE
const cfM=b('202020202020202020207b2f2a20e29480e29480204341534820464c4f5720e29480e29480202a2f7d0d0a202020202020202020207b7461623d3d3d2263617368666c6f7722');
const cfE=b('202020202020202020207d2928297d');
const cfN=b('');
if(!src.includes(cfN)){
  const s=src.indexOf(cfM),e=src.indexOf(cfE,s)+cfE.length;
  if(s<0){console.error('NOT FOUND: cashflow IIFE');process.exit(1);}
  src=Buffer.concat([src.slice(0,s),cfN,src.slice(e)]);
  done.push('10. Cashflow IIFE');
}else{skipped.push('10. Cashflow IIFE');}


// 11. NSF customer search — also search by phone, address, paidBy
ap('11. NSF customer search',
  b(''),
  b(''));


// 12. filtSales search — also search by paidBy and address
ap('12. filtSales paidBy+address search',
  b(''),
  b(''));

fs.writeFileSync(FILE,src);
console.log('\n=== ROS BMS Patch Complete ===');
done.forEach(d=>console.log('  APPLIED: '+d));
skipped.forEach(s=>console.log('  SKIPPED: '+s));
console.log('\nSize: '+src.length+' bytes');
console.log('\nNow run:');
console.log('  git add src/App.jsx');
console.log('  git commit -m "fix: all features"');
console.log('  git push origin main');
